// One-shot generator: walks svg/{event,unofficial,penalty}/*.svg and emits
// svg-map.ts with a literal-string Record<string,string>. Replaces Vite's
// import.meta.glob('./svg/{...}/*.svg', { query: '?raw', eager: true }).
// Re-run via: node packages/client-next/components/EventIcon/gen-svg-map.mjs

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const here = path.dirname(fileURLToPath(import.meta.url));
const out = [
  '// Auto-generated by gen-svg-map.mjs — do not edit by hand.',
  '// Re-run the generator if SVGs are added/changed.',
  '',
  'export const SVG_BY_KEY: Record<string, string> = {',
];

for (const kind of ['event', 'unofficial', 'penalty']) {
  const dir = path.join(here, 'svg', kind);
  if (!fs.existsSync(dir)) continue;
  for (const f of fs.readdirSync(dir).sort()) {
    if (!f.endsWith('.svg')) continue;
    const name = f.replace(/\.svg$/, '');
    const raw = fs.readFileSync(path.join(dir, f), 'utf8').trim();
    // Use a template literal; escape backslash, backtick, and ${ — nothing else.
    const escaped = raw
      .replace(/\\/g, '\\\\')
      .replace(/`/g, '\\`')
      .replace(/\$\{/g, '\\${');
    out.push(`  ${JSON.stringify(`${kind}-${name}`)}: \`${escaped}\`,`);
  }
}
out.push('};', '');

fs.writeFileSync(path.join(here, 'svg-map.ts'), out.join('\n'));
console.log('wrote svg-map.ts');
